@startuml
!theme base

class "LoadModelHandler" {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class "CreateNewLocalizationhandler" {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class "UpdateLocalizationHandler" {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class "VisualizePSHandler" {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class "VisualizeDGHandler" {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class "NewModelHandler" {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class "PolicyModelService" {
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class "PolicyModelHttpHandler" {
  + splitQuery(String query): Map<String, String>
  + getRequestBody(HttpExchange httpExchange): String
  + handle(HttpExchange httpExchange)
  + getRequestParam(HttpExchange httpExchange): Map<String, String>
  + handleGetRequest(Map<String, String> params): String
  + handlePostRequest(String body): Pair<Integer, String>
}

class "HttpHandler" {
  <<external library>>
  <<Interface>>
}

class "jackson-annotations" {
  <<external libraries>>
}

class "jackson-core" {
  <<external libraries>>
}

class "jackson-databind" {
  <<external libraries>>
}

"LoadModelHandler" --|> "PolicyModelHttpHandler"
"CreateNewLocalizationhandler" --|> "PolicyModelHttpHandler"
"UpdateLocalizationHandler" --|> "PolicyModelHttpHandler"
"VisualizePSHandler" --|> "PolicyModelHttpHandler"
"VisualizeDGHandler" --|> "PolicyModelHttpHandler"
"NewModelHandler" --|> "PolicyModelHttpHandler"

"PolicyModelService" ..> "LoadModelHandler" : uses
"PolicyModelService" ..> "CreateNewLocalizationhandler" : uses
"PolicyModelService" ..> "UpdateLocalizationHandler" : uses
"PolicyModelService" ..> "VisualizePSHandler" : uses
"PolicyModelService" ..> "VisualizeDGHandler" : uses
"PolicyModelService" ..> "NewModelHandler" : uses

"PolicyModelHttpHandler" ..> "HttpHandler"
"NewModelHandler" ..> "jackson-annotations" : uses
"NewModelHandler" ..> "jackson-core" : uses
"NewModelHandler" ..> "jackson-databind" : uses

@enduml
